import React, { useState } from 'react';
import { useLocation, useNavigate } from 'react-router-dom';
import { FaWallet, FaCheck, FaCoins, FaArrowLeft } from 'react-icons/fa';

const Payment = () => {
  const location = useLocation();
  const navigate = useNavigate();
  const { amount = 0.5, task, response } = location.state || {};
  const [isProcessing, setIsProcessing] = useState(false);
  const [isComplete, setIsComplete] = useState(false);

  const handlePayment = async () => {
    setIsProcessing(true);
    // Mock payment processing
    setTimeout(() => {
      setIsProcessing(false);
      setIsComplete(true);
      setTimeout(() => {
        navigate('/dashboard');
      }, 2000);
    }, 2000);
  };

  if (isComplete) {
    return (
      <div className="min-h-screen bg-gradient-to-br from-green-50 to-blue-50 flex items-center justify-center p-4">
        <div className="max-w-md w-full bg-white rounded-2xl shadow-xl p-8 text-center">
          <div className="bg-green-100 w-20 h-20 rounded-full flex items-center justify-center mx-auto mb-6">
            <FaCheck className="text-green-600 text-3xl" />
          </div>
          <h1 className="text-3xl font-bold text-gray-900 mb-4">Payment Successful!</h1>
          <p className="text-gray-600 mb-6">Your transaction has been completed on the Algorand blockchain.</p>
          <div className="bg-gray-50 rounded-lg p-4">
            <p className="text-sm text-gray-500">Redirecting to dashboard...</p>
          </div>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-gradient-to-br from-blue-50 to-purple-50 p-4">
      <div className="max-w-2xl mx-auto">
        {/* Header */}
        <div className="flex items-center mb-8">
          <button
            onClick={() => navigate(-1)}
            className="flex items-center text-gray-600 hover:text-gray-900 mr-4"
          >
            <FaArrowLeft className="mr-2" />
            Back
          </button>
        </div>

        {/* Payment Card */}
        <div className="bg-white rounded-2xl shadow-xl p-8">
          <div className="text-center mb-8">
            <div className="bg-blue-100 w-20 h-20 rounded-full flex items-center justify-center mx-auto mb-4">
              <FaWallet className="text-blue-600 text-3xl" />
            </div>
            <h1 className="text-3xl font-bold text-gray-900 mb-2">Complete Payment</h1>
            <p className="text-gray-600">Secure payment using Algorand blockchain</p>
          </div>

          {/* Payment Details */}
          <div className="bg-gray-50 rounded-xl p-6 mb-6">
            <div className="flex items-center justify-between mb-4">
              <span className="text-gray-600">Service</span>
              <span className="font-medium text-gray-900">AI Agent Response</span>
            </div>
            <div className="flex items-center justify-between mb-4">
              <span className="text-gray-600">Amount</span>
              <div className="flex items-center">
                <FaCoins className="text-yellow-500 mr-1" />
                <span className="font-bold text-xl text-gray-900">{amount} ALGO</span>
              </div>
            </div>
            <div className="border-t pt-4">
              <div className="flex items-center justify-between">
                <span className="font-medium text-gray-900">Total</span>
                <div className="flex items-center">
                  <FaCoins className="text-yellow-500 mr-1" />
                  <span className="font-bold text-2xl text-gray-900">{amount} ALGO</span>
                </div>
              </div>
            </div>
          </div>

          {/* Wallet Info */}
          <div className="bg-blue-50 rounded-xl p-6 mb-6">
            <h3 className="font-medium text-gray-900 mb-2">Connected Wallet</h3>
            <div className="flex items-center justify-between">
              <div className="flex items-center">
                <FaWallet className="text-blue-600 mr-2" />
                <span className="text-sm font-mono text-gray-700">ALGO...WXYZ</span>
              </div>
              <span className="text-green-600 text-sm font-medium">Connected</span>
            </div>
          </div>

          {/* Payment Button */}
          <button
            onClick={handlePayment}
            disabled={isProcessing}
            className="w-full bg-gradient-to-r from-green-600 to-blue-600 text-white py-4 px-6 rounded-lg font-medium text-lg hover:from-green-700 hover:to-blue-700 transition-all transform hover:scale-105 disabled:opacity-50 disabled:cursor-not-allowed inline-flex items-center justify-center"
          >
            {isProcessing ? (
              <>
                <div className="animate-spin rounded-full h-5 w-5 border-b-2 border-white mr-2"></div>
                Processing Payment...
              </>
            ) : (
              <>
                Confirm Payment
                <FaCoins className="ml-2" />
              </>
            )}
          </button>

          {/* Security Note */}
          <p className="text-center text-sm text-gray-500 mt-4">
            Your payment is secured by Algorand blockchain technology
          </p>
        </div>
      </div>
    </div>
  );
};

export default Payment;
